import React from 'react'
import '@testing-library/jest-dom'
import { render, screen, fireEvent, act } from '@testing-library/react'

export const testIds = {
    container: 'split-payment-container',
    amount: 'total-amount',
    plans: 'plans-grid',
    installments: 'installments-list',
}

jest.mock('./useData', () => ({
    __esModule: true,
    default: jest.fn(),
    getTotalAmount: jest.fn(),
    getPlansData: jest.fn(),
    getInstallments: jest.fn(),
    calculateInstallments: jest.requireActual('./useData').calculateInstallments,
}))

beforeEach(() => {
    jest.clearAllMocks()
    useSplitPaymentStore.setState({ plans: [], totalAmount: null, activePlan: null, planSchedule: null })
})

// 1. Title shows the total amount fetched from the API
it('displays total amount in Title after data loads', () => {
    useData.mockReturnValue({ data: 24435, loading: false, error: null, refetch: jest.fn() })
    useSplitPaymentStore.setState({ totalAmount: 24435 })
    render(<Title />)
    expect(screen.getByTestId(testIds.amount)).toHaveTextContent('Total Amount: Rs 24435')
})

// 2. Plans renders all plan cards
it('renders all plan cards when data is available', () => {
    const mockPlans = [
        { planTitle: '24x', planDuration: '24', id: 'plan-1' },
        { planTitle: '12x', planDuration: '12', id: 'plan-2' },
        { planTitle: '6x', planDuration: '6', id: 'plan-3' },
        { planTitle: '3x', planDuration: '3', id: 'plan-4' },
    ]
    useData.mockReturnValue({ data: mockPlans, loading: false, error: null, refetch: jest.fn() })
    render(<Plans />)
    expect(screen.getByTestId(testIds.plans)).toBeInTheDocument()
    mockPlans.forEach((plan) => expect(screen.getByText(plan.planTitle)).toBeInTheDocument())
})

// 3. Clicking a plan card updates the active plan in the store
it('sets activePlan in store when a plan card is clicked', () => {
    const mockPlans = [{ planTitle: '12x', planDuration: '12', id: 'plan-2' }]
    useData.mockReturnValue({ data: mockPlans, loading: false, error: null, refetch: jest.fn() })
    render(<Plans />)
    fireEvent.click(screen.getByText('12x'))
    expect(useSplitPaymentStore.getState().activePlan).toEqual(mockPlans[0])
})

// 4. PlanSchedule renders installment rows when data is available
it('renders installment rows in PlanSchedule', () => {
    const mockSchedule = [
        { dueDate: '2026-04-01', dueDateLabel: 'Today', dueAmt: 8145 },
        { dueDate: '2026-05-01', dueDateLabel: '1 May 2026', dueAmt: 8145 },
        { dueDate: '2026-06-01', dueDateLabel: '1 Jun 2026', dueAmt: 8145 },
    ]
    useData.mockReturnValue({ data: mockSchedule, loading: false, error: null, refetch: jest.fn() })
    render(<PlanSchedule />)
    expect(screen.getByTestId(testIds.installments)).toBeInTheDocument()
    expect(screen.getByText('due Today')).toBeInTheDocument()
})

// 5. calculateInstallments splits the total correctly
it('calculateInstallments divides total amount into equal parts', async () => {
    jest.useFakeTimers()
    const promise = calculateInstallments(3, 24435)
    act(() => jest.runAllTimers())
    const result = await promise
    expect(result).toHaveLength(3)
    expect(result[0].dueAmt).toBeCloseTo(8145, 0)
    jest.useRealTimers()
})
